var countPrefixSuffixPairs = function(words) {
    let count = 0;
    for (let i = 0; i < words.length; i++) {
        for (let j = i + 1; j < words.length; j++) {
            const s1 = words[i], s2 = words[j];
            if (s1.length <= s2.length && s2.startsWith(s1) && s2.endsWith(s1)) {
                count++;
            }
        }
    }
    return count;
};
